import{_ as a,o as i,c as s,a3 as t}from"./chunks/framework.B4Nz3hZ_.js";const u=JSON.parse(`{"title":"FAQ","description":"","frontmatter":{"head":[["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"FAQPage\\",\\"mainEntity\\":[{\\"@type\\":\\"Question\\",\\"name\\":\\"What shells are supported?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"amoxide supports Fish (fully), PowerShell 5.1+7, Zsh, Bash 3.2+, and Brush (bash-compatible). Nushell support is planned.\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"How is amoxide different from shell aliases in dotfiles?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Traditional aliases are static and defined once in .bashrc or .zshrc. amoxide adds: Profiles (named groups you can activate/deactivate), Project aliases (auto-loaded per directory like direnv), Parameterized aliases (template syntax for composable commands), and multiple active profiles with layered precedence.\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"Where are my aliases stored?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Global aliases are stored in ~/.config/amoxide/config.toml. Profile aliases are stored in ~/.config/amoxide/profiles.toml. Project aliases are stored in a .aliases file in the project directory.\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"Can I use amoxide alongside my existing shell aliases?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Yes. amoxide aliases coexist with your shell's native aliases. If there is a name conflict, amoxide's alias takes precedence while it is active.\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"What is am-tui?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"am-tui is a separate binary (amoxide-tui) that provides an interactive terminal UI for managing aliases visually. Run it with: am tui. Install via: brew install sassman/tap/amoxide-tui\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"I changed my config file manually — how do I apply the changes without restarting my shell?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Run am init -f <shell> to reinitialise in place. This unloads all current aliases and reloads everything from your config, including any setting changes like use_abbr = true in Fish.\\"}}]}"]]},"headers":[],"relativePath":"faq.md","filePath":"faq.md"}`),l={name:"faq.md"};function n(o,e,r,d,h,p){return i(),s("div",null,[...e[0]||(e[0]=[t("",19)])])}const g=a(l,[["render",n]]);export{u as __pageData,g as default};
